parameters.functionCode:
// Filter Windows servers
const devices = $json.results || $json.devices || $json;
const servers = (Array.isArray(devices) ? devices : []).filter(d => (d.nodeClass||'').includes('WINDOWS_SERVER'));
return servers.map(d => ({ json: { deviceId: d.id, deviceName: d.systemName || 'Unknown', nodeClass: d.nodeClass }}));

const start = new Date($json.WINDOW_START).getTime() / 1000;
const end = new Date($json.WINDOW_END).getTime() / 1000;
const acts = $json.activities || [];
const inWindow = acts.filter(a => (a.activityTime||0) >= start && (a.activityTime||0) <= end);
const hasReboot = inWindow.some(a => a.statusCode === 'SYSTEM_REBOOTED' || (/System rebooted/i).test(a.message||''));
const patchIssues = inWindow.filter(a => (a.activityResult === 'FAILURE') || (/FAILED|ERROR/i).test(a.statusCode||'') || (/download error|failed|blocked/i).test(a.message||''));
const postScan = inWindow.some(a => (/post reboot scan is required/i).test(a.message||''));
if (!hasReboot && patchIssues.length === 0 && !postScan) {
  return [];
}
const linkBase = $json.LINK_BASE || '';
return [{
  json: {
    deviceId: $json.deviceId,
    deviceName: $json.deviceName,
    rebooted: hasReboot,
    patchIssues: patchIssues.length,
    postRebootScanRequired: postScan,
    link: linkBase ? `${linkBase}/${$json.deviceId}/overview` : '',
    windowStart: $json.WINDOW_START,
    windowEnd: $json.WINDOW_END
  }
}];

// Deduplicate per device/window using static data
const key = `${$json.windowStart}|${$json.deviceId}`;
const store = this.getWorkflowStaticData('global');
if (store[key]) { return []; }
store[key] = true;
return [{ json: $json }];

